var EventEmitter = require("events");

function Downloader() {
  EventEmitter.call(this);
}
Downloader.prototype = Object.create(EventEmitter.prototype);

Downloader.prototype.download = function(url) {
  var self = this;
  self.emit("start", url);

  setTimeout(function() {
    if (!url) {
      self.emit("error", new Error("URL is required"));
      return;
    }
    self.emit("progress", { url: url, pct: 50 });
    setTimeout(function() {
      self.emit("complete", { url: url, data: "file content" });
    }, 500);
  }, 500);
};

var dl = new Downloader();
dl.on("start", function(u) { console.log("Starting:", u); });
dl.on("progress", function(p) { console.log(p.pct + "% done"); });
dl.on("complete", function(r) { console.log("Done:", r.data); });
dl.on("error", function(err) { console.error("Error:", err.message); });

dl.download("https://example.com/file.zip");

var EventEmitter = require("events");
var emitter = new EventEmitter();

// Simulate accidental listener leak
setInterval(function() {
  emitter.on("data", function() {
    // This anonymous function cannot be removed later
  });
  var count = emitter.listenerCount("data");
  if (count > 10) {
    console.warn("Warning: " + count + " listeners on data event");
  }
  if (count > 20) {
    console.error("Leak detected! Removing all listeners.");
    emitter.removeAllListeners("data");
  }
}, 1000);

// Proper pattern: store listener reference
var handler = function() { /* handle data */ };
emitter.on("data", handler);
// Later: emitter.removeListener("data", handler);

// Check if emitter has listeners
console.log("Has listeners:", emitter.emit("data") ? "yes" : "no");

var EventEmitter = require("events");

var eventBus = new EventEmitter();
eventBus.setMaxListeners(100);

// Publisher
function publish(event, data) {
  console.log("Publishing:", event);
  eventBus.emit(event, data);
}

// Subscriber
function subscribe(event, handler) {
  eventBus.on(event, handler);
  return function unsubscribe() {
    eventBus.off(event, handler);
  };
}

var unsub = subscribe("order:created", function(order) {
  console.log("New order: " + order.id);
  // Send email, update inventory, charge card
});

publish("order:created", { id: 123, item: "Widget", qty: 2 });

// Later: unsubscribe
unsub();

publish("order:created", { id: 124, item: "Gadget", qty: 1 });
// This does not trigger the first handler (unsubscribed)

